import { hexConcat } from '@ethersproject/bytes';
import { keccak256 } from '@ethersproject/keccak256';
import { toUtf8Bytes } from '@ethersproject/strings';

import type { PaliAuthenticatorModuleId } from './contracts';

export const PALI_CREATE2_DEPLOYER_ADDRESS =
  '0x4e59b44847b379578588920cA78FbF26c0B4956C';

export const PALI_CANONICAL_ENTRYPOINT_ADDRESS =
  '0x433709009B8330FDa32311DF1C2AFA402eD8D009';

export const PALI_CREATE2_DEPLOYER_MIN_RUNTIME_BYTE_LENGTH = 1;
export const PALI_INFRASTRUCTURE_VERSION = 'PALI_SMART_ACCOUNT_ERC7579_V1';

// EntryPoint v0.9 is the official account-abstraction v0.9.0 artifact (solc 0.8.28, via-IR, runs=1_000_000).
// Pali contracts are generated with official EVM solc 0.8.26, via-IR, optimizer enabled, runs=200.
const bytecodes = {
  entryPoint:
    '',
  accountImplementation:
    '',
  ecdsaValidator:
    '',
  p256WebAuthnValidator:
    '',
  compositeValidator:
    '',
  guardianRecoveryModule:
    '',
  factory:
    '',
} as const;

export type PaliInfrastructureContractId = keyof typeof bytecodes;

export type PaliInfrastructureContract = {
  address: string;
  bytecodeHash: string;
  deployCalldata: string;
  displayName: string;
  id: PaliInfrastructureContractId;
  moduleId?: PaliAuthenticatorModuleId;
  salt: string;
};

const salt = (name: string) =>
  keccak256(toUtf8Bytes(`${PALI_INFRASTRUCTURE_VERSION}:${name}`));

const deployCalldata = (contractSalt: string, initCode: string) =>
  hexConcat([contractSalt, initCode]);

const create2Address = (contractSalt: string, initCode: string) =>
  `0x${keccak256(
    hexConcat([
      '0xff',
      PALI_CREATE2_DEPLOYER_ADDRESS,
      contractSalt,
      keccak256(initCode),
    ])
  ).slice(-40)}`;

const entryPointSalt =
  '0x7702864008ddeab30aa67b7adc3d2653bc8d162714b1fe8fe4582df814f3bf61';
const accountImplementationSalt = salt('account-implementation');
const ecdsaValidatorSalt = salt('ecdsa-validator');
const p256WebAuthnValidatorSalt = salt('p256-webauthn-validator');
const compositeValidatorSalt = salt('composite-validator');
const guardianRecoveryModuleSalt = salt('guardian-recovery-module');
const factorySalt = salt('factory');

export const PALI_INFRASTRUCTURE_CONTRACTS: PaliInfrastructureContract[] = [
  {
    address: PALI_CANONICAL_ENTRYPOINT_ADDRESS,
    bytecodeHash: keccak256(bytecodes.entryPoint),
    deployCalldata: deployCalldata(entryPointSalt, bytecodes.entryPoint),
    displayName: 'ERC-4337 EntryPoint v0.9',
    id: 'entryPoint',
    salt: entryPointSalt,
  },
  {
    address: create2Address(
      accountImplementationSalt,
      bytecodes.accountImplementation
    ),
    bytecodeHash: keccak256(bytecodes.accountImplementation),
    deployCalldata: deployCalldata(
      accountImplementationSalt,
      bytecodes.accountImplementation
    ),
    displayName: 'Pali smart account implementation',
    id: 'accountImplementation',
    salt: accountImplementationSalt,
  },
  {
    address: create2Address(ecdsaValidatorSalt, bytecodes.ecdsaValidator),
    bytecodeHash: keccak256(bytecodes.ecdsaValidator),
    deployCalldata: deployCalldata(
      ecdsaValidatorSalt,
      bytecodes.ecdsaValidator
    ),
    displayName: 'ECDSA validator module',
    id: 'ecdsaValidator',
    moduleId: 'ecdsa',
    salt: ecdsaValidatorSalt,
  },
  {
    address: create2Address(
      p256WebAuthnValidatorSalt,
      bytecodes.p256WebAuthnValidator
    ),
    bytecodeHash: keccak256(bytecodes.p256WebAuthnValidator),
    deployCalldata: deployCalldata(
      p256WebAuthnValidatorSalt,
      bytecodes.p256WebAuthnValidator
    ),
    displayName: 'P-256 passkey validator module',
    id: 'p256WebAuthnValidator',
    moduleId: 'p256-webauthn',
    salt: p256WebAuthnValidatorSalt,
  },
  {
    address: create2Address(
      compositeValidatorSalt,
      bytecodes.compositeValidator
    ),
    bytecodeHash: keccak256(bytecodes.compositeValidator),
    deployCalldata: deployCalldata(
      compositeValidatorSalt,
      bytecodes.compositeValidator
    ),
    displayName: 'Composite validator module',
    id: 'compositeValidator',
    moduleId: 'composite',
    salt: compositeValidatorSalt,
  },
  {
    address: create2Address(
      guardianRecoveryModuleSalt,
      bytecodes.guardianRecoveryModule
    ),
    bytecodeHash: keccak256(bytecodes.guardianRecoveryModule),
    deployCalldata: deployCalldata(
      guardianRecoveryModuleSalt,
      bytecodes.guardianRecoveryModule
    ),
    displayName: 'Guardian recovery module',
    id: 'guardianRecoveryModule',
    moduleId: 'guardian-recovery',
    salt: guardianRecoveryModuleSalt,
  },
  {
    // Lean OZ ERC-7579 factory bytecode with the implementation constructor arg appended.
    address: create2Address(factorySalt, bytecodes.factory),
    bytecodeHash: keccak256(bytecodes.factory),
    deployCalldata: deployCalldata(factorySalt, bytecodes.factory),
    displayName: 'Pali ERC-7579 smart account factory',
    id: 'factory',
    salt: factorySalt,
  },
];

export const PALI_INFRASTRUCTURE_BY_ID = Object.fromEntries(
  PALI_INFRASTRUCTURE_CONTRACTS.map((contract) => [contract.id, contract])
) as Record<PaliInfrastructureContractId, PaliInfrastructureContract>;

export const PALI_MODULE_CANONICAL_ADDRESSES: Record<
  PaliAuthenticatorModuleId,
  string
> = {
  composite: PALI_INFRASTRUCTURE_BY_ID.compositeValidator.address,
  ecdsa: PALI_INFRASTRUCTURE_BY_ID.ecdsaValidator.address,
  'guardian-recovery': PALI_INFRASTRUCTURE_BY_ID.guardianRecoveryModule.address,
  'p256-webauthn': PALI_INFRASTRUCTURE_BY_ID.p256WebAuthnValidator.address,
};

export const PALI_CANONICAL_FACTORY_ADDRESS =
  PALI_INFRASTRUCTURE_BY_ID.factory.address;
